import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { DashboardStats } from '../types';
import api from '../utils/api';
import { useAuth } from '../hooks/useAuth';

function getGreeting() {
  const h = new Date().getHours();
  if (h >= 5  && h < 12) return 'Good Morning';
  if (h >= 12 && h < 17) return 'Good Afternoon';
  if (h >= 17 && h < 21) return 'Good Evening';
  return 'Good Night';
}

export default function Dashboard() {
  const { user } = useAuth();
  const navigate = useNavigate();
  const [stats, setStats] = useState<DashboardStats | null>(null);
  const [loading, setLoading] = useState(true);
  const isStaff = user?.userType === 'user';

  useEffect(() => {
    api.get('/borrows/stats').then(r=>{setStats(r.data.data);setLoading(false);}).catch(()=>setLoading(false));
  }, []);

  if (loading) return (
    <div style={{display:'flex',alignItems:'center',justifyContent:'center',height:'100vh'}}>
      <div style={{width:32,height:32,border:'3px solid #c9a84c',borderTopColor:'transparent',borderRadius:'50%',animation:'spin 1s linear infinite'}}/>
    </div>
  );

  const cards = [
    { label:'Total Books',    value:stats?.totalBooks||0,    accent:'#6366f1', tag:'Library'  },
    { label:'Active Members', value:stats?.totalMembers||0,  accent:'#10b981', tag:'Enrolled' },
    { label:'Books Out',      value:stats?.activeBorrows||0, accent:'#c9a84c', tag:'Active'   },
    { label:'Overdue',        value:stats?.overdueBorrows||0,accent:'#ef4444', tag:'Urgent'   },
  ];

  const roleDisplay = user?.role==='librarian'?'Head Librarian':user?.role==='library_assistant'?'Asst. Librarian':user?.role==='student'?'Student':'Staff Member';

  return (
    <div className="page-enter" style={{padding:'28px 36px',width:'100%'}}>
      <style>{`
        .scard{transition:all .22s !important;}
        .scard:hover{transform:translateY(-3px) !important;box-shadow:0 16px 40px rgba(0,0,0,0.4) !important;}
        .al-btn{transition:all .18s !important;cursor:pointer !important;}
        .al-btn:hover{filter:brightness(1.08);}
        .lrow{border-radius:10px;transition:background .15s !important;}
        .lrow:hover{background:rgba(255,255,255,0.04) !important;}
      `}</style>

      {/* ── Header ── */}
      <div style={{display:'flex',alignItems:'center',justifyContent:'space-between',marginBottom:28,gap:16}}>
        <div>
          <p style={{fontSize:11,color:'var(--text-muted)',letterSpacing:'2px',textTransform:'uppercase',marginBottom:8,fontWeight:600}}>
            {new Date().toLocaleDateString('en-US',{weekday:'long',year:'numeric',month:'long',day:'numeric'})}
          </p>
          <h1 style={{fontFamily:"'Playfair Display',serif",fontSize:32,fontWeight:700,color:'var(--text)',lineHeight:1.15,letterSpacing:'-0.3px'}}>
            {getGreeting()}, {user?.name?.split(' ')[0]}
          </h1>
          <p style={{fontSize:13,color:'var(--text-dim)',marginTop:6}}>
            Welcome to the BAUST Library Management System
          </p>
        </div>
        {/* Role badge — centered */}
        <div style={{background:'rgba(201,168,76,0.08)',border:'1px solid rgba(201,168,76,0.15)',borderRadius:14,padding:'12px 20px',display:'flex',flexDirection:'column',alignItems:'center',justifyContent:'center',textAlign:'center',flexShrink:0,minWidth:130}}>
          <div style={{fontSize:10,color:'var(--text-muted)',letterSpacing:'1.5px',textTransform:'uppercase',fontWeight:700,marginBottom:5}}>Signed in as</div>
          <div style={{fontSize:15,fontWeight:800,color:'#c9a84c'}}>{roleDisplay}</div>
          {user?.member_id && <div style={{fontSize:11,color:'rgba(255,255,255,0.25)',marginTop:4,fontFamily:'monospace'}}>ID: {user.member_id}</div>}
        </div>
      </div>

      {/* ── Alerts ── */}
      {isStaff && stats && stats.pendingMembers>0 && (
        <div className="al-btn" onClick={()=>navigate('/members?status=pending')}
          style={{background:'rgba(245,158,11,0.07)',border:'1px solid rgba(245,158,11,0.18)',borderRadius:12,padding:'14px 20px',marginBottom:12,display:'flex',alignItems:'center',gap:14}}>
          <div style={{flex:1}}>
            <div style={{fontSize:14,fontWeight:700,color:'#fbbf24',marginBottom:2}}>{stats.pendingMembers} account(s) waiting for approval</div>
            <div style={{fontSize:12,color:'rgba(251,191,36,0.45)'}}>Click to review pending members</div>
          </div>
          <span style={{fontSize:18,color:'rgba(251,191,36,0.4)'}}>→</span>
        </div>
      )}
      {isStaff && stats && stats.pendingRequests>0 && (
        <div className="al-btn" onClick={()=>navigate('/requests')}
          style={{background:'rgba(99,102,241,0.07)',border:'1px solid rgba(99,102,241,0.18)',borderRadius:12,padding:'14px 20px',marginBottom:22,display:'flex',alignItems:'center',gap:14}}>
          <div style={{flex:1}}>
            <div style={{fontSize:14,fontWeight:700,color:'#a5b4fc',marginBottom:2}}>{stats.pendingRequests} borrow request(s) pending</div>
            <div style={{fontSize:12,color:'rgba(165,180,252,0.45)'}}>Click to review and approve</div>
          </div>
          <span style={{fontSize:18,color:'rgba(165,180,252,0.4)'}}>→</span>
        </div>
      )}

      {stats && (
        <>
          {/* ── Stat Cards ── */}
          <div style={{display:'grid',gridTemplateColumns:'repeat(4,1fr)',gap:16,marginBottom:22}}>
            {cards.map(c=>(
              <div key={c.label} className="scard"
                style={{background:'var(--bg2)',border:'1px solid var(--border)',borderRadius:18,padding:'20px 20px 18px',position:'relative',overflow:'hidden'}}>
                <div style={{position:'absolute',top:-15,right:-15,width:90,height:90,background:c.accent+'18',borderRadius:'50%',filter:'blur(28px)',pointerEvents:'none'}}/>
                <div style={{display:'flex',justifyContent:'flex-end',marginBottom:16}}>
                  <span style={{fontSize:11,fontWeight:700,padding:'3px 11px',borderRadius:99,background:c.accent+'18',color:c.accent,letterSpacing:'.5px',border:`1px solid ${c.accent}28`}}>{c.tag}</span>
                </div>
                <div style={{fontFamily:"'Playfair Display',serif",fontSize:44,fontWeight:700,color:'var(--text)',lineHeight:1,marginBottom:6,letterSpacing:'-1px'}}>{c.value}</div>
                <div style={{fontSize:13,color:'var(--text-dim)',fontWeight:500,marginBottom:14}}>{c.label}</div>
                <div style={{height:2,background:'rgba(255,255,255,0.05)',borderRadius:99,overflow:'hidden'}}>
                  <div style={{height:'100%',width:c.value>0?'60%':'5%',background:`linear-gradient(90deg,${c.accent},${c.accent}55)`,borderRadius:99}}/>
                </div>
              </div>
            ))}
          </div>

          {/* ── Bottom ── */}
          <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:18}}>
            <div style={{background:'var(--bg2)',border:'1px solid var(--border)',borderRadius:18,padding:'22px 24px'}}>
              <div style={{display:'flex',alignItems:'center',justifyContent:'space-between',marginBottom:18}}>
                <h3 style={{fontFamily:"'Playfair Display',serif",fontSize:17,fontWeight:700,color:'var(--text)'}}>Recent Borrows</h3>
                <span style={{fontSize:11,color:'var(--text-muted)',background:'var(--bg3)',border:'1px solid var(--border)',padding:'3px 11px',borderRadius:99,fontWeight:600}}>Latest 5</span>
              </div>
              {stats.recentBorrows.length ? stats.recentBorrows.map((b:any)=>(
                <div key={b.id} className="lrow" style={{display:'flex',alignItems:'center',gap:12,padding:'10px 12px',marginBottom:3}}>
                  <div style={{width:7,height:7,borderRadius:'50%',flexShrink:0,
                    background:b.status==='returned'?'#34d399':b.status==='overdue'?'#f87171':'#fbbf24',
                    boxShadow:`0 0 6px ${b.status==='returned'?'#34d399':b.status==='overdue'?'#f87171':'#fbbf24'}99`}}/>
                  <div style={{flex:1,minWidth:0}}>
                    <div style={{fontSize:13,fontWeight:600,color:'var(--text)',overflow:'hidden',textOverflow:'ellipsis',whiteSpace:'nowrap'}}>{b.title}</div>
                    <div style={{fontSize:11,color:'var(--text-dim)',marginTop:2}}>{b.member_name}</div>
                  </div>
                  <span style={{fontSize:11,fontWeight:700,padding:'3px 10px',borderRadius:99,flexShrink:0,textTransform:'capitalize',
                    background:b.status==='returned'?'rgba(52,211,153,0.1)':b.status==='overdue'?'rgba(248,113,113,0.1)':'rgba(251,191,36,0.1)',
                    color:b.status==='returned'?'#34d399':b.status==='overdue'?'#f87171':'#fbbf24'
                  }}>{b.status}</span>
                </div>
              )) : <div style={{textAlign:'center',padding:'28px 0',color:'var(--text-muted)',fontSize:13,fontStyle:'italic'}}>No borrows yet</div>}
            </div>

            <div style={{background:'var(--bg2)',border:'1px solid var(--border)',borderRadius:18,padding:'22px 24px'}}>
              <div style={{display:'flex',alignItems:'center',justifyContent:'space-between',marginBottom:18}}>
                <h3 style={{fontFamily:"'Playfair Display',serif",fontSize:17,fontWeight:700,color:'var(--text)'}}>Popular Books</h3>
                <span style={{fontSize:11,color:'var(--text-muted)',background:'var(--bg3)',border:'1px solid var(--border)',padding:'3px 11px',borderRadius:99,fontWeight:600}}>Top 5</span>
              </div>
              {stats.popularBooks.length ? stats.popularBooks.map((b:any,i:number)=>(
                <div key={b.title} className="lrow" style={{display:'flex',alignItems:'center',gap:12,padding:'10px 12px',marginBottom:3}}>
                  <div style={{width:26,height:26,borderRadius:7,flexShrink:0,display:'flex',alignItems:'center',justifyContent:'center',fontSize:12,fontWeight:800,
                    background:i===0?'linear-gradient(135deg,#c9a84c,#a87d30)':i===1?'rgba(148,163,184,0.12)':i===2?'rgba(180,100,60,0.12)':'rgba(255,255,255,0.04)',
                    color:i===0?'#1a1a2e':i===1?'#94a3b8':i===2?'#b47844':'rgba(255,255,255,0.25)',
                    boxShadow:i===0?'0 3px 10px rgba(201,168,76,0.4)':'none'
                  }}>{i+1}</div>
                  <div style={{flex:1,minWidth:0}}>
                    <div style={{fontSize:13,fontWeight:600,color:'var(--text)',overflow:'hidden',textOverflow:'ellipsis',whiteSpace:'nowrap'}}>{b.title}</div>
                    <div style={{fontSize:11,color:'var(--text-dim)',marginTop:2}}>{b.author}</div>
                  </div>
                  <div style={{fontSize:13,fontWeight:800,color:'#c9a84c',flexShrink:0}}>{b.borrow_count}×</div>
                </div>
              )) : <div style={{textAlign:'center',padding:'28px 0',color:'var(--text-muted)',fontSize:13,fontStyle:'italic'}}>No data yet</div>}
            </div>
          </div>
        </>
      )}
    </div>
  );
}
